const mongoose = require('mongoose');

main().catch(err => console.error(err));

async function main() {
  await mongoose.connect('mongodb://localhost:27017/shop');
  console.log('Connected to MongoDB');

  const productSchema = new mongoose.Schema({
    name: { type: String, required: true },
    price: { type: Number, required: true },
    description: String,
    inStock: { type: Boolean, default: true }
  });

  const Product = mongoose.model('Product', productSchema);

  // Create
  const p1 = await Product.create({ name: 'Laptop', price: 999, description: 'Gaming laptop' });
  const p2 = await Product.create({ name: 'Mouse', price: 25, description: 'Wireless mouse' });
  const p3 = await Product.create({ name: 'Keyboard', price: 75, description: 'Mechanical', inStock: false });
  console.log('Created:', p1, p2, p3);

  // Find cheap products
  const cheap = await Product.find({ price: { $lt: 100 } });
  console.log('Products under $100:', cheap);

  // Update
  await Product.updateOne({ name: 'Mouse' }, { price: 20 });
  const updated = await Product.findOne({ name: 'Mouse' });
  console.log('Updated mouse price:', updated);

  // Delete
  await Product.deleteOne({ name: 'Keyboard' });
  const all = await Product.find();
  console.log('All products after deletion:', all);

  await mongoose.disconnect();
}
